#include<bits/stdc++.h>
using namespace std;
int a[500010],b[500010];
struct segment_tree
{
    struct node
    {
        long long l,r,max_a,min_b,max_ab,max_ba,max_aba;
        long long lson,rson;
        long long tag;
        node():tag(0){}
    }a[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].max_a=max(a[a[x].lson].max_a,a[a[x].rson].max_a);
        a[x].min_b=min(a[a[x].lson].min_b,a[a[x].rson].min_b);
        a[x].max_ab=max({a[a[x].lson].max_ab,a[a[x].rson].max_ab,a[a[x].lson].max_a-a[a[x].rson].min_b});
        a[x].max_ba=max({a[a[x].lson].max_ba,a[a[x].rson].max_ba,a[a[x].rson].max_a-a[a[x].lson].min_b});
        a[x].max_aba=max({a[a[x].lson].max_aba,a[a[x].rson].max_aba,a[a[x].lson].max_ab+a[a[x].rson].max_a,a[a[x].lson].max_a+a[a[x].rson].max_ba});
    }
    void pushup(node &x,node lson,node rson)
    {
        x.max_a=max(lson.max_a,rson.max_a);
        x.min_b=min(lson.min_b,rson.min_b);
        x.max_ab=max({lson.max_ab,rson.max_ab,lson.max_a-rson.min_b});
        x.max_ba=max({lson.max_ba,rson.max_ba,rson.max_a-lson.min_b});
        x.max_aba=max({lson.max_aba,rson.max_aba,lson.max_ab+rson.max_a,lson.max_a+rson.max_ba});
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].max_a=::a[l];
            a[x].min_b=::b[l];
            a[x].max_ab=a[x].max_ba=a[x].max_aba=-1e18;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].max_a=::a[p];
            a[x].min_b=::b[p];
            a[x].max_ab=a[x].max_ba=a[x].max_aba=-1e18;
            return;
        }
        update(a[x].lson,p);
        update(a[x].rson,p);
        pushup(x);
    }
    node query(long long x,long long l,long long r)
    {
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x];
        }
        int mid=(a[x].l+a[x].r)>>1;
        if(l<=mid&&r>mid)
        {
            node ans=a[x];
            pushup(ans,query(a[x].lson,l,r),query(a[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(a[x].lson,l,r);
        }
        else
        {
            return query(a[x].rson,l,r);
        }
    }
}t;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&b[i]);
    }
    t.init(1,n);
    while(m--)
    {
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        if(op==1)
        {
            a[x]=y;
            t.update(1,x);
        }
        else if(op==2)
        {
            b[x]=y;
            t.update(1,x);
        }
        else
        {
            printf("%d\n",t.query(1,x,y).max_aba);
        }
    }
    return 0;
}
